  fields jsonb NOT NULL DEFAULT '{}'::jsonb,
  files jsonb NOT NULL DEFAULT '[]'::jsonb,
  menu_item text,
  assigned_to uuid,
  staff_notes text,
  submitted_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now(),
  resolved_at timestamp with time zone,
  due_date date,
  submitted_by uuid,
  delegated_by uuid,
  delegated_at timestamp with time zone,
  client_action_request text,
  client_action_response text,
  client_action_files jsonb DEFAULT '[]'::jsonb,
  user_guide text,
  denial_notes text,
  category text,
  source text NOT NULL DEFAULT 'portal'::text,
  asana_gid text,
  messages jsonb NOT NULL DEFAULT '[]'::jsonb,
  submitted_by_staff uuid,
  CONSTRAINT tickets_pkey PRIMARY KEY (id),
  CONSTRAINT tickets_assigned_to_fkey FOREIGN KEY (assigned_to) REFERENCES staff(id),
  CONSTRAINT tickets_client_id_fkey FOREIGN KEY (client_id) REFERENCES clients(id) ON DELETE SET NULL,
  CONSTRAINT tickets_delegated_by_fkey FOREIGN KEY (delegated_by) REFERENCES staff(id),
  CONSTRAINT tickets_submitted_by_fkey FOREIGN KEY (submitted_by) REFERENCES client_users(id) ON DELETE SET NULL,
  CONSTRAINT tickets_submitted_by_staff_fkey FOREIGN KEY (submitted_by_staff) REFERENCES staff(id) ON DELETE SET NULL,
  CONSTRAINT tickets_category_check CHECK (((category IS NULL) OR (category = ANY (ARRAY['systems'::text, 'website'::text, 'ads'::text, 'other'::text])))),
  CONSTRAINT tickets_priority_check CHECK ((priority = ANY (ARRAY['urgent'::text, 'standard'::text, 'low'::text]))),
  CONSTRAINT tickets_source_check CHECK ((source = ANY (ARRAY['portal'::text, 'asana_import'::text]))),
  CONSTRAINT tickets_status_check CHECK ((status = ANY (ARRAY['open'::text, 'delegated'::text, 'in_progress'::text, 'awaiting_client'::text, 'in_review'::text, 'final_review'::text, 'needs_rework'::text, 'approved'::text, 'done'::text, 'cancelled'::text]))),
  CONSTRAINT tickets_type_check CHECK ((type = ANY (ARRAY['error'::text, 'change'::text, 'build'::text, 'onboarding'::text])))
);
