  FOR ALL TO authenticated
  USING ((EXISTS ( SELECT 1
   FROM staff
  WHERE (staff.user_id = auth.uid()))))
  WITH CHECK ((EXISTS ( SELECT 1
   FROM staff
  WHERE (staff.user_id = auth.uid()))));

