  FOR ALL TO authenticated
  USING ((is_staff() OR (client_id IN ( SELECT my_client_ids() AS my_client_ids))))
  WITH CHECK ((is_staff() OR (client_id IN ( SELECT my_client_ids() AS my_client_ids))));

