CREATE OR REPLACE FUNCTION public.add_business_days(start_date date, n integer)
 RETURNS date
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  result date := start_date;
  added int := 0;
BEGIN
  WHILE added < n LOOP
    result := result + 1;
    IF EXTRACT(DOW FROM result) NOT IN (0, 6) THEN
      added := added + 1;
    END IF;
  END LOOP;
  RETURN result;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.add_scaling_manager_to_client_users()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user_id uuid;
  v_name    text;
  v_email   text;
BEGIN
  IF NEW.scaling_manager_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- For UPDATE, skip if scaling_manager_id didn't actually change
  IF TG_OP = 'UPDATE'
     AND OLD.scaling_manager_id IS NOT DISTINCT FROM NEW.scaling_manager_id THEN
    RETURN NEW;
  END IF;

  SELECT user_id, name, email
    INTO v_user_id, v_name, v_email
  FROM public.staff
  WHERE id = NEW.scaling_manager_id;

  -- Skip if staff has no portal auth user yet — they'll need one before
  -- they can log into the client portal anyway
  IF v_user_id IS NULL THEN
    RETURN NEW;
  END IF;

  INSERT INTO public.client_users (user_id, client_id, name, email, role, status)
  VALUES (v_user_id, NEW.id, v_name, v_email, 'member', 'active')
  ON CONFLICT (user_id, client_id) DO UPDATE
    SET status = 'active';  -- reactivate if previously revoked

  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.auth_user_id_by_email(p_email text)
 RETURNS uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO ''
AS $function$
  SELECT id FROM auth.users WHERE lower(email) = lower(p_email) LIMIT 1;
$function$
;

CREATE OR REPLACE FUNCTION public.clients_online_status()
 RETURNS TABLE(client_id uuid, is_online boolean, last_seen_at timestamp with time zone)
 LANGUAGE sql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT
    cu.client_id,
    bool_or(cu.last_seen_at > (now() - interval '2 minutes')) AS is_online,
    max(cu.last_seen_at) AS last_seen_at
  FROM public.client_users cu
  WHERE cu.status = 'active'
    AND cu.user_id IS NOT NULL
    AND cu.last_seen_at IS NOT NULL
    AND cu.user_id NOT IN (
      SELECT s.user_id FROM public.staff s WHERE s.user_id IS NOT NULL
    )
  GROUP BY cu.client_id;
$function$
;

CREATE OR REPLACE FUNCTION public.create_conversation_for_new_client()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  INSERT INTO public.conversations (client_id, kind)
  VALUES (NEW.id, 'general')
  ON CONFLICT (client_id, kind) DO NOTHING;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.dismiss_onboarding_tracker(p_client_id uuid)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_authorized boolean;
  v_updated int := 0;
BEGIN
  SELECT (p_client_id IN (SELECT my_client_ids())) OR is_admin_staff() INTO v_authorized;
  IF NOT v_authorized THEN
    RETURN 0;
  END IF;

  UPDATE clients
     SET onboarding_tracker_dismissed = true
   WHERE id = p_client_id
     AND COALESCE(onboarding_tracker_dismissed, false) = false;
  GET DIAGNOSTICS v_updated = ROW_COUNT;
  RETURN v_updated;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_onboarding_progress(p_client_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_authorized boolean;
  v_result jsonb;
BEGIN
  SELECT (p_client_id IN (SELECT my_client_ids())) OR is_admin_staff() INTO v_authorized;
  IF NOT v_authorized THEN RETURN NULL; END IF;

  SELECT jsonb_build_object(
    'client_id', c.id,
    'in_progress', true,
    'tracker_dismissed', COALESCE(c.onboarding_tracker_dismissed, false),
    'v2_access', COALESCE(c.v2_access, false),
    'ghl_signup_done', (c.ghl_signup_done_at IS NOT NULL),
    'slack_join_done', (c.slack_join_done_at IS NOT NULL),
    'general_done',
      (c.general_marked_done_at IS NOT NULL
       OR (c.business_name IS NOT NULL AND length(trim(c.business_name)) > 0
           AND c.owner_name IS NOT NULL AND length(trim(c.owner_name)) > 0
           AND c.email IS NOT NULL AND length(trim(c.email)) > 0)),
    'staff_done',     (c.staff_marked_done_at IS NOT NULL),
    'locations_done', (c.locations_marked_done_at IS NOT NULL),
    'brand_done',     (c.brand_marked_done_at IS NOT NULL),
    'offers_done',    (c.offers_marked_done_at IS NOT NULL),
    'kpis_done',      (c.kpi_marked_done_at IS NOT NULL),
    'meta_ads_done',  (c.meta_ads_marked_done_at IS NOT NULL)
  ) INTO v_result
  FROM clients c
  WHERE c.id = p_client_id;
  RETURN v_result;
END;
$function$
;

