CREATE OR REPLACE FUNCTION public.mark_onboarding_section(p_client_id uuid, p_section text, p_done boolean DEFAULT true)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_authorized boolean;
  v_col text;
  v_sql text;
  v_value timestamptz;
BEGIN
  SELECT (p_client_id IN (SELECT my_client_ids())) OR is_admin_staff() INTO v_authorized;
  IF NOT v_authorized THEN RETURN false; END IF;

  v_col := CASE p_section
    WHEN 'ghl_signup' THEN 'ghl_signup_done_at'
    WHEN 'slack_join' THEN 'slack_join_done_at'
    WHEN 'general'    THEN 'general_marked_done_at'
    WHEN 'staff'      THEN 'staff_marked_done_at'
    WHEN 'brand'      THEN 'brand_marked_done_at'
    WHEN 'locations'  THEN 'locations_marked_done_at'
    WHEN 'offers'     THEN 'offers_marked_done_at'
    WHEN 'kpis'       THEN 'kpi_marked_done_at'
    ELSE NULL
  END;
  IF v_col IS NULL THEN RETURN false; END IF;

  v_value := CASE WHEN p_done THEN NOW() ELSE NULL END;
  v_sql := format('UPDATE clients SET %I = $1 WHERE id = $2', v_col);
  EXECUTE v_sql USING v_value, p_client_id;

  RETURN true;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.maybe_create_systems_onboarding_ticket()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_general_done    boolean;
  v_assignee        uuid;
  v_ticket_id       uuid;
  v_body            jsonb;
  v_staff           jsonb;
  v_locations       jsonb;
  v_offers          jsonb;
BEGIN
  IF NEW.systems_onboarding_ticket_id IS NOT NULL THEN
    RETURN NEW;
  END IF;

  v_general_done := (NEW.business_name IS NOT NULL AND length(trim(NEW.business_name)) > 0
                  AND NEW.owner_name    IS NOT NULL AND length(trim(NEW.owner_name)) > 0
                  AND NEW.email         IS NOT NULL AND length(trim(NEW.email)) > 0);

  IF NOT (v_general_done
          AND NEW.staff_marked_done_at     IS NOT NULL
          AND NEW.locations_marked_done_at IS NOT NULL
          AND NEW.brand_marked_done_at     IS NOT NULL
          AND NEW.offers_marked_done_at    IS NOT NULL) THEN
    RETURN NEW;
  END IF;

  SELECT id INTO v_assignee FROM staff
   WHERE role = 'systems_manager'
   ORDER BY created_at ASC NULLS LAST LIMIT 1;

  SELECT COALESCE(jsonb_agg(jsonb_build_object(
           'id', cu.id, 'name', cu.name, 'email', cu.email, 'role', cu.role
         ) ORDER BY cu.created_at), '[]'::jsonb)
    INTO v_staff FROM client_users cu
   WHERE cu.client_id = NEW.id AND cu.status = 'active';

  SELECT COALESCE(jsonb_agg(jsonb_build_object(
           'id', l.id, 'title', l.title, 'address', l.address, 'notes', l.notes
         ) ORDER BY l.sort_order, l.created_at), '[]'::jsonb)
    INTO v_locations FROM locations l
   WHERE l.client_id = NEW.id;

  SELECT COALESCE(jsonb_agg(jsonb_build_object(
           'id', o.id, 'type', o.type, 'title', o.title, 'status', o.status, 'data', o.data
         ) ORDER BY o.sort_order, o.created_at), '[]'::jsonb)
    INTO v_offers FROM offers o
   WHERE o.client_id = NEW.id AND COALESCE(o.status, '') <> 'archived';

  v_body := jsonb_build_object(
    'summary', 'Systems onboarding — ' || COALESCE(NEW.business_name, '(no business name)'),
    'client_id', NEW.id,
    'business_name', NEW.business_name,
    'legal_name',    NEW.legal_name,
    'owner_name',    NEW.owner_name,
    'email',         NEW.email,
    'phone',         NEW.phone,
    'address',       NEW.address,
    'time_zone',     NEW.time_zone,
    'entity_type',   NEW.entity_type,
    'ein',           NEW.ein,
    'website',       NEW.brand_data->>'website_url',
    'domain',        NEW.brand_data->>'domain',
    'marketing_included', COALESCE(NEW.marketing_included, false),
    'slack_channel_id',   NEW.slack_channel_id,
    'ghl', jsonb_build_object(
      'location_id',    NEW.ghl_location_id,
      'company_id',     NEW.ghl_company_id,
      'connect_status', NEW.ghl_connect_status
    ),
    'stripe', jsonb_build_object(
      'account_id',     NEW.stripe_connect_account_id,
      'connect_status', NEW.stripe_connect_status
    ),
    'brand',     COALESCE(NEW.brand_data, '{}'::jsonb),
    'kpis',      COALESCE(NEW.kpi_data, '{}'::jsonb),
    'staff',     v_staff,
    'locations', v_locations,
    'offers',    v_offers,
    'marked_done_at', jsonb_build_object(
      'staff',     NEW.staff_marked_done_at,
      'locations', NEW.locations_marked_done_at,
      'brand',     NEW.brand_marked_done_at,
      'offers',    NEW.offers_marked_done_at
    )
  );

  INSERT INTO tickets (
    client_id, type, status, priority, source, fields, assigned_to,
    submitted_at, updated_at
  ) VALUES (
    NEW.id, 'onboarding', 'open', 'standard', 'portal', v_body, v_assignee,
    NOW(), NOW()
  )
  RETURNING id INTO v_ticket_id;

  UPDATE clients SET systems_onboarding_ticket_id = v_ticket_id WHERE id = NEW.id;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.my_client_ids()
 RETURNS SETOF uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT client_id FROM public.client_users
   WHERE user_id = auth.uid() AND status = 'active'
  UNION
  SELECT c.id FROM public.clients c
    JOIN public.staff s ON s.id = c.scaling_manager_id
   WHERE s.user_id = auth.uid()
$function$
;

CREATE OR REPLACE FUNCTION public.notify_slack_on_new_ticket()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
DECLARE
  v_channel        text;
  v_business       text;
  v_token          text;
  v_title          text;
  v_type_label     text;
  v_priority_pre   text;
  v_message        text;
BEGIN
  -- Look up the client's Slack channel + business name
  SELECT slack_channel_id, COALESCE(business_name, 'Client')
    INTO v_channel, v_business
  FROM public.clients
  WHERE id = NEW.client_id;

  IF v_channel IS NULL THEN
    RETURN NEW; -- No channel configured, skip silently
  END IF;

  SELECT value INTO v_token FROM public.app_secrets WHERE key = 'slack_bot_token';
  IF v_token IS NULL THEN
    RETURN NEW; -- No token, skip
  END IF;

  -- Compose the message
  v_title := COALESCE(NEW.menu_item, NEW.fields->>'title', '(no title)');
  v_type_label := CASE
    WHEN NEW.type = 'error'  THEN '🛠 Error report'
    WHEN NEW.type = 'change' THEN '🔧 Change request'
    WHEN NEW.type = 'build'  THEN '🏗 Build request'
    ELSE '📥 Ticket'
  END;
  v_priority_pre := CASE
    WHEN NEW.priority IN ('urgent','red_alert') THEN '🚨 *URGENT* — '
    ELSE ''
  END;

  v_message := v_priority_pre || v_type_label || ' submitted: *' || v_title || '*' || E'\n' ||
               '_The BAM team has been notified and will follow up shortly._';

  -- Fire-and-forget via pg_net (returns a request id; we don't care about the response)
  PERFORM net.http_post(
    url := 'https://slack.com/api/chat.postMessage',
    headers := jsonb_build_object(
      'Authorization', 'Bearer ' || v_token,
      'Content-Type',  'application/json; charset=utf-8'
    ),
    body := jsonb_build_object(
      'channel', v_channel,
      'text',    v_message,
      'unfurl_links', false
    )
  );

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  -- Never let Slack failures block ticket creation
  RAISE WARNING 'notify_slack_on_new_ticket failed: %', SQLERRM;
  RETURN NEW;
END;
$function$
;

