CREATE OR REPLACE FUNCTION public.resend_invite_candidates(p_hours_since integer DEFAULT 20, p_max_retries integer DEFAULT 7, p_limit integer DEFAULT 50)
 RETURNS TABLE(cu_id uuid, user_id uuid, client_id uuid, email text, name text, retry_count integer, last_outbound timestamp with time zone, business_name text, slack_channel_id text)
 LANGUAGE sql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
  SELECT
    cu.id AS cu_id,
    cu.user_id,
    cu.client_id,
    cu.email,
    COALESCE(cu.name, '') AS name,
    COALESCE(cu.invite_retry_count, 0) AS retry_count,
    COALESCE(
      cu.last_invite_sent_at,
      au.recovery_sent_at,
      au.confirmation_sent_at,
      au.invited_at
    ) AS last_outbound,
    COALESCE(c.business_name, '') AS business_name,
    c.slack_channel_id
  FROM public.client_users cu
  JOIN auth.users au ON au.id = cu.user_id
  JOIN public.clients c ON c.id = cu.client_id
  WHERE au.last_sign_in_at IS NULL
    AND au.email_confirmed_at IS NULL
    AND cu.email IS NOT NULL
    AND COALESCE(cu.invite_retry_count, 0) < p_max_retries
    AND cu.email !~* '@(example\.com|example-not-real\.com|test\.|localhost)$'
    AND (
      COALESCE(
        cu.last_invite_sent_at,
        au.recovery_sent_at,
        au.confirmation_sent_at,
        au.invited_at
      ) IS NULL
      OR COALESCE(
        cu.last_invite_sent_at,
        au.recovery_sent_at,
        au.confirmation_sent_at,
        au.invited_at
      ) < NOW() - (p_hours_since || ' hours')::interval
    )
  ORDER BY COALESCE(
    cu.last_invite_sent_at,
    au.recovery_sent_at,
    au.confirmation_sent_at,
    au.invited_at
  ) NULLS FIRST
  LIMIT p_limit;
$function$
;

