-- ============================================================
-- TRIGGERS
-- ============================================================
CREATE TRIGGER trg_action_items_updated_at BEFORE UPDATE ON public.action_items FOR EACH ROW EXECUTE FUNCTION touch_action_items_updated_at();
CREATE TRIGGER client_users_updated_at BEFORE UPDATE ON public.client_users FOR EACH ROW EXECUTE FUNCTION update_client_users_updated_at();
CREATE TRIGGER clients_auto_add_scaling_manager AFTER INSERT OR UPDATE OF scaling_manager_id ON public.clients FOR EACH ROW EXECUTE FUNCTION add_scaling_manager_to_client_users();
CREATE TRIGGER clients_create_conversation AFTER INSERT ON public.clients FOR EACH ROW EXECUTE FUNCTION create_conversation_for_new_client();
CREATE TRIGGER clients_updated_at BEFORE UPDATE ON public.clients FOR EACH ROW EXECUTE FUNCTION update_clients_updated_at();
CREATE TRIGGER content_tickets_updated_at BEFORE UPDATE ON public.content_tickets FOR EACH ROW EXECUTE FUNCTION set_content_ticket_updated_at();
CREATE TRIGGER conversation_messages_update_parent AFTER INSERT ON public.conversation_messages FOR EACH ROW EXECUTE FUNCTION update_conversation_on_new_message();
CREATE TRIGGER guide_cards_updated_at BEFORE UPDATE ON public.guide_cards FOR EACH ROW EXECUTE FUNCTION set_guide_card_updated_at();
CREATE TRIGGER locations_updated_at BEFORE UPDATE ON public.locations FOR EACH ROW EXECUTE FUNCTION offers_set_updated_at();
CREATE TRIGGER marketing_tickets_updated_at BEFORE UPDATE ON public.marketing_tickets FOR EACH ROW EXECUTE FUNCTION set_marketing_ticket_updated_at();
CREATE TRIGGER members_updated_at BEFORE UPDATE ON public.members FOR EACH ROW EXECUTE FUNCTION update_members_updated_at();
CREATE TRIGGER offer_teams_updated_at BEFORE UPDATE ON public.offer_teams FOR EACH ROW EXECUTE FUNCTION offers_set_updated_at();
CREATE TRIGGER offers_updated_at BEFORE UPDATE ON public.offers FOR EACH ROW EXECUTE FUNCTION offers_set_updated_at();
CREATE TRIGGER pricing_catalog_updated_at BEFORE UPDATE ON public.pricing_catalog FOR EACH ROW EXECUTE FUNCTION update_pricing_catalog_updated_at();
CREATE TRIGGER resources_updated_at BEFORE UPDATE ON public.resources FOR EACH ROW EXECUTE FUNCTION resources_set_updated_at();
CREATE TRIGGER staff_updated_at BEFORE UPDATE ON public.staff FOR EACH ROW EXECUTE FUNCTION update_staff_updated_at();
CREATE TRIGGER tickets_notify_slack_on_insert AFTER INSERT ON public.tickets FOR EACH ROW EXECUTE FUNCTION notify_slack_on_new_ticket();
CREATE TRIGGER tickets_set_due_date_trg BEFORE INSERT ON public.tickets FOR EACH ROW EXECUTE FUNCTION tickets_set_due_date();
CREATE TRIGGER tickets_updated_at BEFORE UPDATE ON public.tickets FOR EACH ROW EXECUTE FUNCTION update_tickets_updated_at();
